const rows = $input.first().json.data || [];

const mapped = rows.map((row) => {
  return {
    json: {
      vehicle_id: row['vehicle_id'] ?? row['차량ID'] ?? row['vehicle'] ?? null,
      date: row['date'] ?? row['날짜'] ?? row['일자'] ?? null,
      location_type: row['location_type'] ?? row['장소유형'] ?? row['위치유형'] ?? null,
      customer_id: row['customer_id'] ?? row['거래처ID'] ?? row['고객ID'] ?? null,
      longitude: parseFloat(row['longitude'] ?? row['경도'] ?? row['lon'] ?? 0),
      latitude: parseFloat(row['latitude'] ?? row['위도'] ?? row['lat'] ?? 0),
      alocated_order_num: parseInt(row['alocated_order_num'] ?? row['할당주문수'] ?? row['배정주문'] ?? 0, 10),
      travel_order: parseInt(row['travel_order'] ?? row['이동차수'] ?? row['경유순서'] ?? 0, 10),
      delivery_cbm: parseFloat(row['delivery_cbm'] ?? row['배송CBM'] ?? row['적재CBM'] ?? 0),
      distance: parseFloat(row['distance'] ?? row['거리'] ?? row['이동거리'] ?? 0),
      running_time: parseFloat(row['running_time'] ?? row['운행시간'] ?? row['소요시간'] ?? 0)
    }
  };
});

return mapped;
